import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSSecureCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by escaping it
        String escapedUserInput = "";
        try {
            escapedUserInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            System.out.println("Error while encoding user input: " + e.getMessage());
        }

        // Rendering properly escaped user input in the output
        String output = "<div>" + escapedUserInput + "</div>";

        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
